OutfitIconNew.DATA_TYPE_COMMON = 1 			-- 通用装备
OutfitIconNew.DATA_TYPE_SET = 2 			-- 装备结构
OutfitIconNew.DATA_TYPE_MY = 3 				-- 自己的装备
function OutfitIconNew:OutfitIconNew(wndClass)
	self._refId = 0
