	-----------------------------------------------------------------
	self._displayStar = 0
	self._displayShowIcon = nil
	self._displayShowIconBg = nil
	self._displayGray = false
	self._displayNum = 0

	self._displayName = nil
	self._displayColor = nil

	self._cacheStar = 0
	self._dataType = 0


	self._id = nil
	self._star = 0
	self._heroRefId = 0
	self._starExp = 0
	self._heroId = nil
	self._classLv = 0

	self._displayZSHeroIcon = nil
	self._limitTxt = ""
	self._showLimitTxt = false
end

function OutfitIconNew:OnDestroy()

end
-----------------------------------------------------------------
function OutfitIconNew:ResetIcon()
	BaseIconNew.ResetIcon(self)

	self._refId = 0
	self._num = nil
	self._star = 0
	self._showGou = false
	self._showNum = false

	self._minIcon = nil
	self._minIconBg = nil
	
	self._id = nil
	self._star = self.star
	self._heroRefId = 0
	self._starExp = 0
	self._heroId = nil
	self._classLv = 0

	self._displayZSHeroIcon = nil
	self._limitTxt = ""
	self._showLimitTxt = false
end

-----------------------------------------------------------------
function OutfitIconNew:ApplyIconUI()
	BaseIconNew.ApplyIconUI(self)

	self:SetIcon(self._displayShowIcon)
	self:SetIconBg(self._displayShowIconBg)

	self:UpdateStarUI()

	self:SetGouTransVisible(self._showGou)
	self:SetOutfitIconGray()

	self:SetNumUIVisible()

	self:SetZSHeroIconVisible()
	self:SetMinIcon(self._displayZSHeroIcon)

	self:ApplyClassLvTxt()
	self:ApplyNumTxt()
	self:ShowLimitTxt()
end

function OutfitIconNew:SetMinIcon(imgPath)
	if imgPath == self._minIcon then return end
	self._minIcon = imgPath
	if not self:IsIconValid() then
		return
	end
	self:UpdateMinIcon()
end

function OutfitIconNew:UpdateMinIcon()
	local imgPath = self._minIcon
	if string.isempty(imgPath) then
		if self._uiZSIconTrans.gameObject.activeSelf then
			CS.ShowObject(self._uiZSIconTrans,false)
		end
		return
	end
	if self._ownerWndClass then
		-- 放在窗体里加载，方便做关联释放
		self._ownerWndClass:SetWndEasyImage(self._uiZSIconTrans, imgPath, function()
			if self:IsDestroy() then return end
			if string.isempty(self._minIcon) then return end
			if self._uiZSIconTrans and CS.IsValidObject(self._uiZSIconTrans) and not self._uiZSIconTrans.gameObject.activeSelf then
				CS.ShowObject(self._uiZSIconTrans,true)
			end
		end)
	else
		self:SetImage(self._uiZSIconTrans, imgPath, function()
			if self:IsDestroy() then return end
			if string.isempty(self._minIcon) then return end
			if self._uiZSIconTrans and CS.IsValidObject(self._uiZSIconTrans) and not self._uiZSIconTrans.gameObject.activeSelf then
				CS.ShowObject(self._uiZSIconTrans,true)
			end
		end)
	end
end

function OutfitIconNew:OnInitTrans()
	local iconInst = self._iconInst
	self._uiNumTxtTrans = CS.FindTrans(iconInst,"NumTxt")
	self._uiStarTrans = CS.FindTrans(iconInst,"StarList")
	self._uiGouTrans = CS.FindTrans(iconInst,"GouImg")
	self._uiLvTxtTrans = CS.FindTrans(iconInst,"LvTxt")
	self._uiZSIconTrans = CS.FindTrans(iconInst,"ZSIcon")
	self._uiLimitBgTrans = CS.FindTrans(iconInst,"LimitBg")
	self._uiLimitTrans = CS.FindTrans(self._uiLimitBgTrans,"Limit")
	self:InitStartList()
end

-----------------------------------------------------------------
function OutfitIconNew:EnableShowNum(bShow)
	self._showNum = bShow
	self:UpdateNumData()
end

function OutfitIconNew:ShowNum(b)
	self._showNum = b

	self:UpdateNumData()

	if not self:IsIconValid() then return end

	self:SetNumUIVisible()

end

function OutfitIconNew:UpdateNumData()
	self._displayNum = self._num or 0
end
--[[
function OutfitIconNew:EnableShowNum(bShow)
	self._hideNum = not bShow
end]]

function OutfitIconNew:SetNumUIVisible()
	local b = self._showNum and self._showNum or false

	if self._uiNumTxtTrans.gameObject.activeSelf ~= b then
		CS.ShowObject(self._uiNumTxtTrans, b)
	end
end

function OutfitIconNew:ApplyNumTxt()
	if not self._showNum then return end
	local num = self._displayNum
	local numStr = tostring(num)
	if not num or num == -1 or num == 0 then
		numStr = ""
	end
	self:SetXUIText(self._uiNumTxtTrans,numStr)
end

function OutfitIconNew:SetItemNum(num)
	self._num = num

	self:UpdateNumData()

	if not self:IsIconValid() then return end
	self:ApplyNumTxt()
end

function OutfitIconNew:SetOutfitStar(star)
	self._displayStar = star
end

function OutfitIconNew:SetZSHeroRefId(zsHero)
	if self._heroRefId == zsHero then return end
	self._heroRefId = zsHero
	self:SetZSHeroIcon()
end

function OutfitIconNew:SetZSHeroIconVisible()
	local zsHero = self._heroRefId or 0
	if not self:IsIconValid() then return end
	local show = zsHero ~= 0
	CS.ShowObject(self._uiZSIconTrans,show)
end

function OutfitIconNew:SetShowGouImg(b)
	b = b or false and true
	self._showGou = b
end

function OutfitIconNew:ShowGouImg(b)
	if self._showGou == b then return end
	self._showGou = b

	if not self:IsIconValid() then return end

	self:SetGouTransVisible(self._showGou)
	self:SetOutfitIconGray()
end

function OutfitIconNew:SetGouTransVisible(bVisible)
	bVisible = bVisible and bVisible or false
	local gameObj = self._uiGouTrans.gameObject
	if gameObj.activeSelf ~= bVisible then
		CS.ShowObject(gameObj, bVisible)
	end
end

function OutfitIconNew:SetOutfitIconGray()
	local b = self._showGou
	self:SetImageGray(self._uiIconBgTrans,b)
	self:SetImageGray(self._uiIconTrans,b)
	self:SetImageGray(self._uiZSIconTrans,b)
end
-----------------------------------------------------------------
function OutfitIconNew:SetOutfitCommon(refId,itemNun)
	self._dataType = OutfitIconNew.DATA_TYPE_COMMON

	self._refId = refId
	self._num = itemNun

	self:InitInfo()
end

function OutfitIconNew:SetOutfitData(outfitData)
	self._dataType = OutfitIconNew.DATA_TYPE_SET

	self._id = outfitData.id
	self._refId = outfitData.refId
	self._star = outfitData.star
	self._heroRefId = outfitData.heroRefId
	self._starExp = outfitData.starExp
	self._heroId = outfitData.heroId

	self:InitInfo()
end

function OutfitIconNew:SetOutfitId(outfitId)
	self._dataType = OutfitIconNew.DATA_TYPE_MY
	self._id = outfitId
	self:InitInfo()
end
-----------------------------------------------------------------

function OutfitIconNew:InitInfo()
	local star = 0
	local refId = 0
	local heroRefId = 0
	local iconPath = nil
	local iconBgPath = nil
	local itemName = nil
	local itemColor = nil
	local heroIcon = nil

	if self._dataType == OutfitIconNew.DATA_TYPE_SET then
		refId = self._refId
		star = self._star
		heroRefId = self._heroRefId

	elseif self._dataType == OutfitIconNew.DATA_TYPE_MY then
		local id = self._id
		if id and gModelOutfit then
			local serverData = gModelOutfit:GetOutfitServerDataById(id)
			if serverData then
				refId = serverData.refId
				star = serverData.star
				heroRefId = serverData.heroRefId
			end
		end
	elseif self._dataType == OutfitIconNew.DATA_TYPE_COMMON then
		refId = self._refId
	end

	self._heroRefId = heroRefId

	self:SetZSHeroIcon()

	local classLv = 0

	local outfitRef = self:GetOutfitRef(refId)
	if outfitRef then
		iconPath = outfitRef.icon
		itemName = ccLngText(outfitRef.name)
		local quality = outfitRef.quality
		local qualityRef = self:GetItemQualityRef(quality)
		if qualityRef then
			iconBgPath = qualityRef.iconBg
			local color = qualityRef.nameColor
			if color then
				itemColor = LUtil.ColorByHex(color)
			end
		end
		classLv = outfitRef.classShow
		self._isOutfit = true
	else
		self._isOutfit = false
		self._showNum = false
		local partRef = self:GetOutfitPartRef(self._refId)
		if partRef then
			iconPath = partRef.emptyIcon
			iconBgPath = "public_item_bg_1"
		else
			iconPath = "public_item_bg_add"
		end
	end

	self._displayStar = star
	self._displayName = itemName
	self._displayColor = itemColor
	self._displayShowIcon = iconPath
	self._displayShowIconBg = iconBgPath
	self._classLv = classLv
	self:UpdateNumData()
end

function OutfitIconNew:SetZSHeroIcon()
	if gModelHero and self._heroRefId > 0 then
		local effRef = gModelHero:GetHeroShowRefByRefId(self._heroRefId)
		if effRef then
			self._displayZSHeroIcon = effRef.outfitIcon
		end
	end
end

function OutfitIconNew:GetNameData()
	return self._displayName,self._displayColor
end

function OutfitIconNew:ApplyClassLvTxt()
	local classLv = self._classLv
	local show = classLv ~= 0
	if show then
		self:SetXUIText(self._uiLvTxtTrans,classLv)
	end
	if self._uiLvTxtTrans.gameObject.activeSelf ~= show then
		CS.ShowObject(self._uiLvTxtTrans, show)
	end
end

function OutfitIconNew:SetLimitTxt(str)
	self._limitTxt = str
	self._showLimitTxt = not string.isempty(str)
	self:ShowLimitTxt()
end

function OutfitIconNew:ShowLimitTxt()
	if not CS.IsValidObject(self._uiLimitTrans) then
		return
	end
	CS.ShowObject(self._uiLimitTrans.parent,self._showLimitTxt)
	if not self._showLimitTxt then
		return
	end

	local size
	if gLGameLanguage:IsForeignVersion() then
		size = 16
	end
	self:SetXUIText(self._uiLimitTrans,self._limitTxt, size)
end

-----------------------------------------------------------------
function OutfitIconNew:GetOutfitRef(refId)

	return GameTable.OutfitRef[refId]
end

function OutfitIconNew:GetOutfitPartRef(refId)

	return GameTable.OutfitPartRef[refId]
end

-----------------------------------------------------------------
return OutfitIconNew